    const indicesOfOne = [];
    const indicesOfTwo = [];

    // 1. Find all indices where nums[i] is 1 or 2
    for (let i = 0; i < nums.length; i++) {
        if (nums[i] === 1) {
            indicesOfOne.push(i);
        } else if (nums[i] === 2) {
            indicesOfTwo.push(i);
        }
    }

    // 2. Check if any valid pair exists
    if (indicesOfOne.length === 0 || indicesOfTwo.length === 0) {
        return -1;
    }

    let minDiff = Infinity;

